3.6 Analytical Metrics
To support deeper analysis, we will create derived metrics from the cleaned dataset.


Code
library(tidyverse)
library(here)

energy_clean &lt;- readr::read_csv(here::here("data", "energy_data_clean.csv"))

fuel_metrics &lt;- energy_clean |&gt;
  filter(Panel == "Fuels") |&gt;
  mutate(
    fossil_grp = Fuel_Type %in% c("Oil", "Coal", "Natural gas"),
    low_carbon_grp = Fuel_Type %in% c("Electricity", "Bioenergy", "Other fuels")
  ) |&gt;
  group_by(Country) |&gt;
  summarise(
    fossil_fuel_share = sum(Percentage[fossil_group], na.rm = TRUE),
    low_carbon_share = sum(Percentage[low_carbon_group], na.rm = TRUE),
    electr_share = sum(Percentage[Fuel_Type == "Electricity"], na.rm = TRUE),
    .groups = "drop"
  )

sector_metrics &lt;- energy_clean |&gt;
  filter(Panel == "Sector") |&gt;
  group_by(Country) |&gt;
  summarise(
    indstr_share = sum(Percentage[End_Use_Sector == "Industry"], na.rm = TRUE),
    trnsprt_share = sum(Percentage[End_Use_Sector == "Transport"], na.rm = TRUE),
    bldngs_share = sum(Percentage[End_Use_Sector == "Buildings"], na.rm = TRUE),
    .groups = "drop"
  )

energy_metrics &lt;- fuel_metrics |&gt;
  left_join(sector_metrics, by = "Country")


These derived metrics allow the final report to answer stronger analytical questions:

Which countries are most dependent on fossil fuels?
Which countries show higher electricity use?
Which countries have energy demand mainly driven by industry?
Are fuel-mix differences linked to sector-demand differences?

This strengthens the project because the improved visualization is not only more readable, but al so supports evidence-based interpretation.
